import asyncio
import json
import time
import math
import random
from dataclasses import dataclass, asdict
from typing import Dict, List, Set
from collections import defaultdict

@dataclass
class Vector3:
    x: float
    y: float
    z: float
    
    def distance_to(self, other):
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )
    
    def to_dict(self):
        return {'x': self.x, 'y': self.y, 'z': self.z}

@dataclass
class Player:
    player_id: str
    position: Vector3
    rotation: Vector3
    health: int
    alive: bool
    kills: int
    username: str
    team_id: int
    velocity: Vector3
    
    def to_dict(self):
        return {
            'player_id': self.player_id,
            'position': self.position.to_dict(),
            'rotation': self.rotation.to_dict(),
            'health': self.health,
            'alive': self.alive,
            'kills': self.kills,
            'username': self.username,
            'team_id': self.team_id,
            'velocity': self.velocity.to_dict()
        }

class GameState:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.safe_zone_center = Vector3(0, 0, 0)
        self.safe_zone_radius = 1000.0
        self.safe_zone_damage = 5
        self.game_time = 0.0
        self.match_state = "LOBBY"
        self.items = []
        self.airdrops = []
        
    def to_dict(self):
        return {
            'players': {pid: p.to_dict() for pid, p in self.players.items()},
            'safe_zone': {
                'center': self.safe_zone_center.to_dict(),
                'radius': self.safe_zone_radius,
                'damage': self.safe_zone_damage
            },
            'game_time': self.game_time,
            'match_state': self.match_state,
            'items': self.items,
            'airdrops': self.airdrops,
            'alive_count': sum(1 for p in self.players.values() if p.alive)
        }

class BattleRoyaleServer:
    def __init__(self, host='0.0.0.0', port=8888):
        self.host = host
        self.port = port
        self.clients: Dict[str, asyncio.StreamWriter] = {}
        self.game_state = GameState()
        self.tick_rate = 60
        self.broadcast_rate = 20
        self.running = False
        
    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        addr = writer.get_extra_info('peername')
        player_id = f"player_{addr[0]}_{addr[1]}_{int(time.time() * 1000)}"
        
        print(f"New connection from {addr}, assigned ID: {player_id}")
        
        self.clients[player_id] = writer
        
        spawn_position = Vector3(
            random.uniform(-500, 500),
            0,
            random.uniform(-500, 500)
        )
        
        player = Player(
            player_id=player_id,
            position=spawn_position,
            rotation=Vector3(0, 0, 0),
            health=100,
            alive=True,
            kills=0,
            username=f"Player_{len(self.clients)}",
            team_id=0,
            velocity=Vector3(0, 0, 0)
        )
        
        self.game_state.players[player_id] = player
        
        welcome_msg = {
            'type': 'WELCOME',
            'player_id': player_id,
            'spawn_position': spawn_position.to_dict()
        }
        
        await self.send_to_client(writer, welcome_msg)
        
        try:
            while self.running:
                data = await asyncio.wait_for(reader.read(4096), timeout=0.1)
                if not data:
                    break
                    
                try:
                    messages = data.decode().strip().split('\n')
                    for msg_str in messages:
                        if msg_str:
                            message = json.loads(msg_str)
                            await self.handle_message(player_id, message)
                except json.JSONDecodeError:
                    pass
                except Exception as e:
                    print(f"Error handling message: {e}")
                    
        except asyncio.TimeoutError:
            pass
        except Exception as e:
            print(f"Client {player_id} error: {e}")
        finally:
            print(f"Client {player_id} disconnected")
            if player_id in self.clients:
                del self.clients[player_id]
            if player_id in self.game_state.players:
                del self.game_state.players[player_id]
            writer.close()
            await writer.wait_closed()
    
    async def handle_message(self, player_id: str, message: dict):
        msg_type = message.get('type')
        
        if msg_type == 'UPDATE_POSITION':
            if player_id in self.game_state.players:
                player = self.game_state.players[player_id]
                pos_data = message.get('position', {})
                rot_data = message.get('rotation', {})
                vel_data = message.get('velocity', {})
                
                player.position = Vector3(
                    pos_data.get('x', player.position.x),
                    pos_data.get('y', player.position.y),
                    pos_data.get('z', player.position.z)
                )
                player.rotation = Vector3(
                    rot_data.get('x', player.rotation.x),
                    rot_data.get('y', player.rotation.y),
                    rot_data.get('z', player.rotation.z)
                )
                player.velocity = Vector3(
                    vel_data.get('x', 0),
                    vel_data.get('y', 0),
                    vel_data.get('z', 0)
                )
        
        elif msg_type == 'SHOOT':
            target_id = message.get('target_id')
            damage = message.get('damage', 10)
            
            if target_id in self.game_state.players:
                target = self.game_state.players[target_id]
                if target.alive:
                    target.health -= damage
                    
                    if target.health <= 0:
                        target.health = 0
                        target.alive = False
                        if player_id in self.game_state.players:
                            self.game_state.players[player_id].kills += 1
                        
                        kill_event = {
                            'type': 'PLAYER_KILLED',
                            'killer_id': player_id,
                            'victim_id': target_id
                        }
                        await self.broadcast(kill_event)
        
        elif msg_type == 'CHAT':
            chat_msg = {
                'type': 'CHAT',
                'player_id': player_id,
                'username': self.game_state.players[player_id].username,
                'message': message.get('message', '')
            }
            await self.broadcast(chat_msg)
    
    async def send_to_client(self, writer: asyncio.StreamWriter, message: dict):
        try:
            data = json.dumps(message) + '\n'
            writer.write(data.encode())
            await writer.drain()
        except Exception as e:
            print(f"Error sending to client: {e}")
    
    async def broadcast(self, message: dict):
        dead_clients = []
        for player_id, writer in self.clients.items():
            try:
                await self.send_to_client(writer, message)
            except Exception as e:
                print(f"Error broadcasting to {player_id}: {e}")
                dead_clients.append(player_id)
        
        for player_id in dead_clients:
            if player_id in self.clients:
                del self.clients[player_id]
            if player_id in self.game_state.players:
                del self.game_state.players[player_id]
    
    async def broadcast_game_state(self):
        while self.running:
            try:
                state_message = {
                    'type': 'GAME_STATE',
                    'timestamp': time.time(),
                    'state': self.game_state.to_dict()
                }
                
                await self.broadcast(state_message)
                
                await asyncio.sleep(1.0 / self.broadcast_rate)
            except Exception as e:
                print(f"Error broadcasting game state: {e}")
                await asyncio.sleep(0.1)
    
    async def game_loop(self):
        last_tick = time.time()
        tick_interval = 1.0 / self.tick_rate
        
        while self.running:
            current_time = time.time()
            delta_time = current_time - last_tick
            
            if delta_time >= tick_interval:
                self.game_state.game_time += delta_time
                
                self.update_safe_zone()
                self.apply_safe_zone_damage()
                self.check_win_condition()
                
                last_tick = current_time
            
            await asyncio.sleep(0.001)
    
    def update_safe_zone(self):
        if self.game_state.match_state == "PLAYING":
            shrink_rate = 0.5
            self.game_state.safe_zone_radius = max(
                50.0,
                self.game_state.safe_zone_radius - shrink_rate
            )
    
    def apply_safe_zone_damage(self):
        for player in self.game_state.players.values():
            if player.alive:
                distance = player.position.distance_to(self.game_state.safe_zone_center)
                if distance > self.game_state.safe_zone_radius:
                    player.health -= self.game_state.safe_zone_damage
                    if player.health <= 0:
                        player.health = 0
                        player.alive = False
    
    def check_win_condition(self):
        alive_players = [p for p in self.game_state.players.values() if p.alive]
        
        if len(alive_players) == 1 and self.game_state.match_state == "PLAYING":
            self.game_state.match_state = "ENDED"
            
        elif len(alive_players) >= 2 and self.game_state.match_state == "LOBBY":
            self.game_state.match_state = "PLAYING"
    
    async def start(self):
        self.running = True
        
        server = await asyncio.start_server(
            self.handle_client,
            self.host,
            self.port
        )
        
        addr = server.sockets[0].getsockname()
        print(f"Battle Royale Server started on {addr}")
        
        game_loop_task = asyncio.create_task(self.game_loop())
        broadcast_task = asyncio.create_task(self.broadcast_game_state())
        
        async with server:
            await server.serve_forever()

if __name__ == '__main__':
    server = BattleRoyaleServer()
    asyncio.run(server.start())